package logger

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/logger"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type LoggerProxy struct {
	logger.UnimplementedLoggerServer
	client logger.LoggerClient
}

func init() {
	proxyutil.Register(&logger.Logger_ServiceDesc, NewLoggerProxy)
}
func NewLoggerProxy(cc grpc.ClientConnInterface) logger.LoggerServer {
	return &LoggerProxy{client: logger.NewLoggerClient(cc)}
}
func (p *LoggerProxy) Error(ctx context.Context, in *logger.LogErrorMessage) (*logger.LogErrorResponse, error) {
	return proxyutil.ProxyMethod[logger.LogErrorMessage, logger.LogErrorResponse](p.client.Error)(ctx, in)
}
func (p *LoggerProxy) Event(ctx context.Context, in *logger.LogEventMessage) (*logger.LogEventResponse, error) {
	return proxyutil.ProxyMethod[logger.LogEventMessage, logger.LogEventResponse](p.client.Event)(ctx, in)
}
func (p *LoggerProxy) Log(ctx context.Context, in *logger.LogMessage) (*logger.LogResponse, error) {
	return proxyutil.ProxyMethod[logger.LogMessage, logger.LogResponse](p.client.Log)(ctx, in)
}
func (p *LoggerProxy) LogBatch(ctx context.Context, in *logger.LogMessages) (*logger.LogResponse, error) {
	return proxyutil.ProxyMethod[logger.LogMessages, logger.LogResponse](p.client.LogBatch)(ctx, in)
}
